package org.apache.commons.codec.binary;

/**
 * This class provides utility methods for working with CharSequence objects.
 * This is a simplified version for Apache Commons Codec.
 */
public class CharSequenceUtils {

    /**
     * Returns a new CharSequence that is a subsequence of this sequence.
     * The subsequence starts with the character at the specified index and
     * ends with the character at index {@code end - 1}.
     *
     * @param cs the specified sequence
     * @param beginIndex the beginning index, inclusive
     * @param endIndex the ending index, exclusive
     * @return a new subsequence
     */
    public static CharSequence subSequence(CharSequence cs, int beginIndex, int endIndex) {
        if (cs instanceof String) {
            return ((String) cs).substring(beginIndex, endIndex);
        } else if (cs instanceof StringBuilder) {
            return ((StringBuilder) cs).substring(beginIndex, endIndex);
        } else if (cs instanceof StringBuffer) {
            return ((StringBuffer) cs).substring(beginIndex, endIndex);
        } else if (cs instanceof char[]) {
            char[] subarray = new char[endIndex - beginIndex];
            System.arraycopy(cs, beginIndex, subarray, 0, subarray.length);
            return new String(subarray);
        } else {
            // For other CharSequence implementations, convert to string
            return cs.subSequence(beginIndex, endIndex);
        }
    }

    /**
     * Check if a CharSequence starts with a specified prefix.
     *
     * @param str the CharSequence to check
     * @param prefix the prefix to check for
     * @return true if the CharSequence starts with the prefix
     */
    public static boolean startsWith(CharSequence str, CharSequence prefix) {
        if (str == null || prefix == null) {
            return str == prefix;
        }
        if (prefix.length() > str.length()) {
            return false;
        }
        // Use regionMatches to efficiently compare regions
        return regionMatches(str, 0, prefix, 0, prefix.length());
    }

    /**
     * Performs a region matches on two CharSequences.
     *
     * @param cs1 the first CharSequence
     * @param offset1 the starting offset in the first CharSequence
     * @param cs2 the second CharSequence
     * @param offset2 the starting offset in the second CharSequence
     * @param length the number of characters to match
     * @return true if the region matches, false otherwise
     */
    static boolean regionMatches(CharSequence cs1, int offset1, CharSequence cs2, int offset2, int length) {
        // Check for null values
        if (cs1 == null || cs2 == null) {
            return cs1 == cs2;
        }

        // Check for valid ranges
        if (offset1 < 0 || offset2 < 0 || length < 0) {
            return false;
        }

        // Check if ranges are within bounds
        if (offset1 + length > cs1.length() || offset2 + length > cs2.length()) {
            return false;
        }

        // Compare characters one by one
        for (int i = 0; i < length; i++) {
            if (cs1.charAt(offset1 + i) != cs2.charAt(offset2 + i)) {
                return false;
            }
        }

        return true;
    }
}

