    /**
     * Returns a new CharSequence that is a subsequence of this sequence.
     */
    public static CharSequence subSequence(CharSequence cs, int beginIndex, int endIndex) {
        if (cs == null) {
            return null;
        }
        return cs.subSequence(beginIndex, endIndex);
    }

    /**
     * Performs a region matches on two CharSequences with optional case sensitivity.
     * This is the main method that may have had bugs in the original implementation.
     */
    static boolean regionMatches(CharSequence cs1, boolean ignoreCase, int offset1, CharSequence cs2, int offset2, int length) {
        // Handle nulls
        if (cs1 == null || cs2 == null) {
            return cs1 == cs2;
        }

        // Bounds checks - critical bug fix
        if (offset1 < 0 || offset2 < 0) {
            return false;
        }
        if (offset1 > cs1.length() || offset2 > cs2.length()) {
            return false;
        }
        if (length < 0) {
            return false;
        }
        if (offset1 + length > cs1.length() || offset2 + length > cs2.length()) {
            return false;
        }

        // Character comparison loop - the critical part for locale issues
        for (int i = 0; i < length; i++) {
            char c1 = cs1.charAt(offset1 + i);
            char c2 = cs2.charAt(offset2 + i);

            if (c1 == c2) {
                continue; // Same character, continue
            }

            if (!ignoreCase) {
                return false; // Different characters, case sensitive comparison
            }

            // Case insensitive comparison
            // FIX: Avoid locale-sensitive transformations like Character.toLowerCase/UpperCase
            // Use ASCII-specific conversion
            if (c1 != c2) {
